export const SpanProcessorSchema = z.object({ "batch": BatchSpanProcessorSchema.describe("Configure a batch span processor.\nIf omitted, ignore.\n").optional(), "simple": SimpleSpanProcessorSchema.describe("Configure a simple span processor.\nIf omitted, ignore.\n").optional() }).catchall(z.union([z.null(), z.record(z.string(), z.any())]));

export const TracerProviderSchema = z.object({ "processors": z.array(SpanProcessorSchema).describe("Configure span processors.\nProperty is required and must be non-null.\n"), "limits": SpanLimitsSchema.describe("Configure span limits. See also attribute_limits.\nIf omitted, default values as described in SpanLimits are used.\n").optional(), "sampler": SamplerSchema.describe("Configure the sampler.\nIf omitted, parent based sampler with a root of always_on is used.\n").optional(), "tracer_configurator/development": ExperimentalTracerConfiguratorSchema.describe("Configure tracers.\nIf omitted, all tracers use default values as described in ExperimentalTracerConfig.\n").optional() }).strict();

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export const OpenTelemetryConfigurationSchema: z.ZodTypeAny = z.object({ "file_format": z.string().describe("The file format version.\nRepresented as a string including the semver major, minor version numbers (and optionally the meta tag). For example: \"0.4\", \"1.0-rc.2\", \"1.0\" (after stable release).\nSee https://github.com/open-telemetry/opentelemetry-configuration/blob/main/VERSIONING.md for more details.\nThe yaml format is documented at https://github.com/open-telemetry/opentelemetry-configuration/tree/main/schema\nProperty is required and must be non-null.\n"), "disabled": z.union([z.null().describe("Configure if the SDK is disabled or not.\nIf omitted or null, false is used.\n"), z.boolean().describe("Configure if the SDK is disabled or not.\nIf omitted or null, false is used.\n")]).describe("Configure if the SDK is disabled or not.\nIf omitted or null, false is used.\n").optional(), "log_level": SeverityNumberSchema.describe("Configure the log level of the internal logger used by the SDK.\nValues include:\n* debug: debug, severity number 5.\n* debug2: debug2, severity number 6.\n* debug3: debug3, severity number 7.\n* debug4: debug4, severity number 8.\n* error: error, severity number 17.\n* error2: error2, severity number 18.\n* error3: error3, severity number 19.\n* error4: error4, severity number 20.\n* fatal: fatal, severity number 21.\n* fatal2: fatal2, severity number 22.\n* fatal3: fatal3, severity number 23.\n* fatal4: fatal4, severity number 24.\n* info: info, severity number 9.\n* info2: info2, severity number 10.\n* info3: info3, severity number 11.\n* info4: info4, severity number 12.\n* trace: trace, severity number 1.\n* trace2: trace2, severity number 2.\n* trace3: trace3, severity number 3.\n* trace4: trace4, severity number 4.\n* warn: warn, severity number 13.\n* warn2: warn2, severity number 14.\n* warn3: warn3, severity number 15.\n* warn4: warn4, severity number 16.\nIf omitted, INFO is used.\n").optional(), "attribute_limits": AttributeLimitsSchema.describe("Configure general attribute limits. See also tracer_provider.limits, logger_provider.limits.\nIf omitted, default values as described in AttributeLimits are used.\n").optional(), "logger_provider": LoggerProviderSchema.describe("Configure logger provider.\nIf omitted, a noop logger provider is used.\n").optional(), "meter_provider": MeterProviderSchema.describe("Configure meter provider.\nIf omitted, a noop meter provider is used.\n").optional(), "propagator": PropagatorSchema.describe("Configure text map context propagators.\nIf omitted, a noop propagator is used.\n").optional(), "tracer_provider": TracerProviderSchema.describe("Configure tracer provider.\nIf omitted, a noop tracer provider is used.\n").optional(), "resource": ResourceSchema.describe("Configure resource for all signals.\nIf omitted, the default resource is used.\n").optional(), "instrumentation/development": ExperimentalInstrumentationSchema.describe("Configure instrumentation.\nIf omitted, instrumentation defaults are used.\n").optional(), "distribution": DistributionSchema.describe("Defines configuration parameters specific to a particular OpenTelemetry distribution or vendor.\nThis section provides a standardized location for distribution-specific settings\nthat are not part of the OpenTelemetry configuration model.\nIt allows vendors to expose their own extensions and general configuration options.\nIf omitted, distribution defaults are used.\n").optional() }).catchall(z.any());
